Die so abgerufenen Treffer können entweder direkt weiterverarbeitet oder lokal zwischengespeichert werden. Im Folgenden werden die Ergebnisse in eine XML-Datei geschrieben, die heruntergeladen werden kann:

with open('sru_abfrage_klimawandel.xml', 'w', encoding="utf-8") as f:    f.write(str(myquery))

Step 2 — Idempotency check helper
Before creating an item, search existing items by DNB IDN to avoid duplicates.

import requests as req

def find_item_by_idn(idn):
    """Return QID of an existing item with this DNB IDN, or None."""
    sparql = f"""
        SELECT ?item WHERE {{
          ?item wdt:{P_DNB_IDN} "{idn}" .
        }} LIMIT 1
    """
    try:
        resp = req.get(
            wbi_config["SPARQL_ENDPOINT_URL"],
            params={"query": sparql, "format": "json"},
            timeout=15,
        )
        bindings = resp.json()["results"]["bindings"]
        if bindings:
            return bindings[0]["item"]["value"].split("/")[-1]
    except Exception:
        pass
    return None

